                            let ny_usize = ny as usize;
                            if !visited[nx_usize][ny_usize] && grid[nx_usize][ny_usize] > 0 {
                                visited[nx_usize][ny_usize] = true;
                                queue.push_back((nx_usize, ny_usize));
                                sum += grid[nx_usize][ny_usize];
                            }
                        }
                    }
                }

                if sum % k == 0 {
                    count += 1;
                }
            }
        }
    }

    count
}
